('RD-000013', 'Acáami', 'Acáami', 'acaami', NULL, 'Adj', 'Adj', '1. Salado 2. Dulce', '["Salado","Dulce"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 3, 3, 'Transcrito'),
('RD-000014', 'Acáanami', 'Acáanami', 'acaanami', NULL, 'Adj', 'Adj', 'Sano de pie o de brazo (se usa negativamente)', '["Sano de pie o de brazo (se usa negativamente)"]', '["Echi rijoy que acáanami ju, mapujiti binoy ronórachi nacórami ju, Ese hombre es cojo porque tiene la pierna chueca. Que acáanami, cojo. Que acanáami biréana ronochí, cojo de una pierna."]', '[]', 'Echi rijoy que acáanami ju, mapujiti binoy ronórachi nacórami ju, Ese hombre es cojo porque tiene la pierna chueca. Que acáanami, cojo. Que acanáami biréana ronochí, cojo de una pierna.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 3, 3, 'Transcrito'),
('RD-000015', 'Acabó', 'Acabó', 'acabo', NULL, 'S', 'S', 'Hoyo de la nariz, ventana de la nariz', '["Hoyo de la nariz, ventana de la nariz"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 3, 3, 'Transcrito'),
('RD-000016', 'Acáchura', 'Acáchura', 'acachura', NULL, 'S', 'S', '1. Abuela paterna 2. Nieta (de la abuela paterna)', '["Abuela paterna","Nieta (de la abuela paterna)"]', '["Echi nijé onorá iyera nijé acáchura ju, la mamá de mi papá es mi abuela paterna. Nijé acáchura, mi abuela (la mamá de mi papá)."]', '[]', 'Echi nijé onorá iyera nijé acáchura ju, la mamá de mi papá es mi abuela paterna. Nijé acáchura, mi abuela (la mamá de mi papá).', 'SRC-02', 'DICCIONARIO raramuri.pdf', 3, 4, 'Transcrito'),
