('RD-000021', 'Acaná', 'Acaná', 'acana', NULL, 'Adv', 'Adv', 'Boca abajo', '["Boca abajo"]', '["Acaná huichiri, se cayó boca abajo. ¡Acaná achá bitori! ¡Voltea el cajete (boca abajo)!"]', '[]', 'Acaná huichiri, se cayó boca abajo. ¡Acaná achá bitori! ¡Voltea el cajete (boca abajo)!', 'SRC-02', 'DICCIONARIO raramuri.pdf', 4, 4, 'Transcrito'),
