('RD-000029', '''Aché', '''Aché', '''ache', NULL, 'Vi', 'Vi', 'Atiesarse (de frío), morirse (de frío)', '["Atiesarse (de frío), morirse (de frío)"]', '["Biré táa tohuí ''acheca mucuri, mapujiti quetasi teri quima, un niño chiquito se atiesó, y murió así, porque no tenía cobija."]', '[]', 'Biré táa tohuí ''acheca mucuri, mapujiti quetasi teri quima, un niño chiquito se atiesó, y murió así, porque no tenía cobija.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 4, 4, 'Transcrito'),
('RD-000030', 'Achí', 'Achí', 'achi', NULL, 'Vt', 'Vt', 'Reír, sonreír', '["Reír, sonreír"]', '["Echi jaré rarámuri huabé achiri maparí nijé huichiri, los tarahumaras se rieron mucho cuando me caí."]', '[]', 'Echi jaré rarámuri huabé achiri maparí nijé huichiri, los tarahumaras se rieron mucho cuando me caí.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 4, 4, 'Transcrito'),
