('RD-000033', 'Achigórigá', 'Achigórigá', 'achigoriga', NULL, 'Adv', 'Adv', 'De la misma manera, así también', '["De la misma manera, así también"]', '["Echi rijoy nihuari biré namuti achigórigá mapurigá rihuari echo''ná huarúrachi, ese hombre hizo una cosa de la misma manera que vió en la ciudad."]', '[]', 'Echi rijoy nihuari biré namuti achigórigá mapurigá rihuari echo''ná huarúrachi, ese hombre hizo una cosa de la misma manera que vió en la ciudad.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 4, 4, 'Transcrito'),
('RD-000034', 'A''huí', 'A''huí', 'a''hui', NULL, 'Vi', 'Vi', 'Brotar, nacer o germinar (semillas)', '["Brotar, nacer o germinar (semillas)"]', '["[pret.: a''huiri, fut.: a''huimea]"]', '["pret.: a''huiri, fut.: a''huimea"]', '[pret.: a''huiri, fut.: a''huimea]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 4, 4, 'Transcrito'),
