('RD-000045', 'Amarú', 'Amarú', 'amaru', NULL, 'Vi', 'Vi', 'Estar entero', '["Estar entero"]', '["Auchériga atí bachí; abijí amarúami ju, así está la cabalaza; todavía está enter."]', '[]', 'Auchériga atí bachí; abijí amarúami ju, así está la cabalaza; todavía está enter.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000046', 'Amarúami', 'Amarúami', 'amaruami', NULL, 'Adj', 'Adj', 'Entero', '["Entero"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000047', 'Amí', 'Amí', 'ami', NULL, 'Vt', 'Vt', 'Buscar', '["Buscar"]', '["Nijeni simea huenomí ámia, voy a buscar dinero Símabo huenomí ábia, vamos a buscar dinero. ¡Amí!, ¡Vaya a buscarlo! Ámia simiri, fue a buscarlo."]', '[]', 'Nijeni simea huenomí ámia, voy a buscar dinero Símabo huenomí ábia, vamos a buscar dinero. ¡Amí!, ¡Vaya a buscarlo! Ámia simiri, fue a buscarlo.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000048', 'Amígohua', 'Amígohua', 'amigohua', NULL, 'S', 'S', 'Amigo', '["Amigo"]', '["Nijé amígohuara, mis amigos"]', '[]', 'Nijé amígohuara, mis amigos', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000049', 'Amóo, amoque', 'Amóo, amoque', 'amoo, amoque', NULL, 'S', 'S', 'Panal, miel de abeja', '["Panal, miel de abeja"]', '["Huamí ripá coráachi chucú biré amóo, allá arriba, en la escarpadura, está colgado un panal."]', '["amoque"]', 'Huamí ripá coráachi chucú biré amóo, allá arriba, en la escarpadura, está colgado un panal.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000050', 'Aná', '1Aná', 'ana', 1, 'Adv', 'Adv', 'De otro modo', '["De otro modo"]', '["Aná cho niráa ra''ichari, habló de otro modo."]', '[]', 'Aná cho niráa ra''ichari, habló de otro modo.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000051', 'Aná', '2Aná', 'ana', 2, 'S', 'S', '1. Ala 2. Aleta', '["Ala","Aleta"]', '["Churuguí anará, alas de pájaro Rochí anará, aletas de pez"]', '[]', 'Churuguí anará, alas de pájaro Rochí anará, aletas de pez', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000052', 'A’nabáa', 'A’nabáa', 'a''nabaa', NULL, 'Vi', 'Vi', 'Juntarse', '["Juntarse"]', '["Jena’í piréami pagótami a’nabáari echo’ná comurachi, la gente de aquí se juntó en la casa de la comunidad"]', '[]', 'Jena’í piréami pagótami a’nabáari echo’ná comurachi, la gente de aquí se juntó en la casa de la comunidad', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000053', 'Anacha', 'Anacha', 'anacha', NULL, 'Vi', 'Vi', 'Aguantar', '["Aguantar"]', '["Maparí rarajípari, échi rijoy quetasi anáchari, cuando corrieron con la bolsa, ese hombre no aguantó. Biquiyá norí chopi anáchari, solamente aguantó tres vueltas. Ne huabé ocó ramichí; nijeni quetasi omero huaminabi anacha, me duele mucho la muela; no puedo aguantarla más. [pret.: anáchari; fut.: anachama]"]', '["pret.: anáchari; fut.: anachama"]', 'Maparí rarajípari, échi rijoy quetasi anáchari, cuando corrieron con la bolsa, ese hombre no aguantó. Biquiyá norí chopi anáchari, solamente aguantó tres vueltas. Ne huabé ocó ramichí; nijeni quetasi omero huaminabi anacha, me duele mucho la muela; no puedo aguantarla más. [pret.: anáchari; fut.: anachama]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000054', 'Anachapa', 'Anachapa', 'anachapa', NULL, 'Vi', 'Vi', 'Aletear', '["Aletear"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000055', 'A’nagú', 'A’nagú', 'a''nagu', NULL, 'Adv', 'Adv', 'Mutuamente, unos a otros', '["Mutuamente, unos a otros"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000056', 'Anahué', 'Anahué', 'anahue', NULL, 'Vi', 'Vi', 'Aletear', '["Aletear"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 5, 'Transcrito'),
('RD-000057', 'Anahui', 'Anahui', 'anahui', NULL, 'Vt', 'Vt', 'Medir, pesar', '["Medir, pesar"]', '["Gará anáhuari echi sunú, mapurigá ibiri chópirigá chapimea, midieron bien el maíz, para que cada uno reciba la misma cantidad. [pret.: anpahuari; fut.: anáhuima]"]', '["pret.: anpahuari; fut.: anáhuima"]', 'Gará anáhuari echi sunú, mapurigá ibiri chópirigá chapimea, midieron bien el maíz, para que cada uno reciba la misma cantidad. [pret.: anpahuari; fut.: anáhuima]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 5, 6, 'Transcrito'),
('RD-000058', 'A’nahuí', 'A’nahuí', 'a''nahui', NULL, 'Adv', 'Adv', '1. Al mismo tiempo 2. igual', '["Al mismo tiempo","igual"]', '["A’nahuí ochérari, nacieron al mismo tiempo. Ne a’nahuí buyari, salieron al mismo tiempo. Ocuánica ne a''nahuí ju, los dos son iguales. A''nahuí ju, son iguales"]', '[]', 'A’nahuí ochérari, nacieron al mismo tiempo. Ne a’nahuí buyari, salieron al mismo tiempo. Ocuánica ne a''nahuí ju, los dos son iguales. A''nahuí ju, son iguales', 'SRC-02', 'DICCIONARIO raramuri.pdf', 6, 6, 'Transcrito'),
('RD-000059', 'A''najata', 'A''najata', 'a''najata', NULL, 'Vt', 'Vt', 'Perseguir', '["Perseguir"]', '["Echi rijoy quimá chigósari, echijiti a''najátabo, ese hombre se robó una cobija; por eso lo perseguiremos. [pret.: a''najátari; fut.: a’najátama]"]', '["pret.: a''najátari; fut.: a’najátama"]', 'Echi rijoy quimá chigósari, echijiti a''najátabo, ese hombre se robó una cobija; por eso lo perseguiremos. [pret.: a''najátari; fut.: a’najátama]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 6, 6, 'Transcrito'),
('RD-000060', 'A''namótami', 'A''namótami', 'a''namotami', NULL, 'Adv', 'Adv', 'Uno encima del otro', '["Uno encima del otro"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 6, 6, 'Transcrito'),
('RD-000061', 'A''namótana', 'A''namótana', 'a''namotana', NULL, 'Vt', 'Vt', 'Poner (uno encima del otro)', '["Poner (uno encima del otro)"]', '["Napabuca a''namótana muchúhuari, las puso una encima de la otra, haciendo un montón."]', '[]', 'Napabuca a''namótana muchúhuari, las puso una encima de la otra, haciendo un montón.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 6, 6, 'Transcrito'),
('RD-000062', 'Anara', 'Anara', 'anara', NULL, 'Vt', 'Vt', 'Igualar', '["Igualar"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 6, 6, 'Transcrito'),
('RD-000063', 'A''nayáhuari', 'A''nayáhuari', 'a''nayahuari', NULL, 'S pl', 'S', 'Los que vivieron hace mucho, los espíritus de los antepasados', '["Los que vivieron hace mucho, los espíritus de los antepasados"]', '["Jaré rarámuri mayé mapu echi jaré qui''yá piréami pagótami arihuá abijí ''yena jena''í, echijiti maparí echi jaré rarámuri huabé majajáratami ju, rocogó niráa, aboni mayé mapu a''nayáhuari ''yena. Algunos tarahumaras creen que los espíritus de los que vivieron hace mucho todavía andan aquí, por eso, cuando ellos están muy asustados en la noche, creen que los espíritus de los antepasados andan por ahí."]', '[]', 'Jaré rarámuri mayé mapu echi jaré qui''yá piréami pagótami arihuá abijí ''yena jena''í, echijiti maparí echi jaré rarámuri huabé majajáratami ju, rocogó niráa, aboni mayé mapu a''nayáhuari ''yena. Algunos tarahumaras creen que los espíritus de los que vivieron hace mucho todavía andan aquí, por eso, cuando ellos están muy asustados en la noche, creen que los espíritus de los antepasados andan por ahí.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 6, 6, 'Transcrito'),
('RD-000064', 'Ané', 'Ané', 'ane', NULL, 'Vt', 'Vt', 'Decir', '["Decir"]', '["Maparí echi rijoy ra''íchari tamí yuhua, binoy tamí aneri mapu binoy onorá ma mucuri, cuando ese hombre habló conmigo, me dijo que su papá ya había muerto."]', '[]', 'Maparí echi rijoy ra''íchari tamí yuhua, binoy tamí aneri mapu binoy onorá ma mucuri, cuando ese hombre habló conmigo, me dijo que su papá ya había muerto.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 6, 6, 'Transcrito'),
('RD-000065', 'Ané', 'Ané', 'ane', NULL, 'Vi', 'Vi', 'Sonar fuerte', '["Sonar fuerte"]', '["Jeané, le dice esto Anebi, le hubiéramos dicho Anemi, le hubiera dicho"]', '[]', 'Jeané, le dice esto Anebi, le hubiéramos dicho Anemi, le hubiera dicho', 'SRC-02', 'DICCIONARIO raramuri.pdf', 6, 6, 'Transcrito'),
