('RD-000097', 'Arihué', 'Arihué', 'arihue', NULL, 'Vt', 'Vt', 'Dejar', '["Dejar"]', '["Rijoy huaminá arihueri binoy upira, el hombre dejó a su esposa. Echo''ná bitichí arihueri ripurá, dejó el hacha en la casa. ¡Arihué! ¡Quetasi namó orá!, ¡Déjalo! iNo le hagas nada! [pp.: arihuérami; fut.: arihuema]"]', '["pp.: arihuérami; fut.: arihuema"]', 'Rijoy huaminá arihueri binoy upira, el hombre dejó a su esposa. Echo''ná bitichí arihueri ripurá, dejó el hacha en la casa. ¡Arihué! ¡Quetasi namó orá!, ¡Déjalo! iNo le hagas nada! [pp.: arihuérami; fut.: arihuema]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 7, 7, 'Transcrito'),
('RD-000098', 'Arimuri', 'Arimuri', 'arimuri', NULL, 'S', 'S', 'Almud', '["Almud"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
('RD-000099', 'A''rínaromí', 'A''rínaromí', 'a''rinaromi', NULL, 'Adv', 'Adv', 'Al poco rato', '["Al poco rato"]', '["Maparimi cu simiri, que ayó, pe a''rínaromí échico nahuarí, a poco de haberse ido usted, llegó él."]', '[]', 'Maparimi cu simiri, que ayó, pe a''rínaromí échico nahuarí, a poco de haberse ido usted, llegó él.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
