('RD-000101', 'Arirí', 'Arirí', 'ariri', NULL, 'Interj', 'Interj', 'iAy!', '["iAy!"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
