('RD-000104', 'Asapa', 'Asapa', 'asapa', NULL, 'Vt', 'Vt', 'Sacudir', '["Sacudir"]', '["Cará asápari quimá, mapujiti hue napisóori. Sacudió bien la cobija, porque tenía mucho polvo."]', '[]', 'Cará asápari quimá, mapujiti hue napisóori. Sacudió bien la cobija, porque tenía mucho polvo.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
('RD-000105', 'Asayé', 'Asayé', 'asaye', NULL, 'S pl', 'S', 'Enemigos', '["Enemigos"]', '["[sing.: sayé]"]', '["sing.: sayé"]', '[sing.: sayé]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
('RD-000106', 'Asé', 'Asé', 'ase', NULL, 'Vt', 'Vt', 'Montar (un animal)', '["Montar (un animal)"]', '["Cahué asigá cu simiri. Montando el caballo, se fué. Que cho binéami ju aserihua. Todavía no está entrenado a ser montado. Asigá montando"]', '[]', 'Cahué asigá cu simiri. Montando el caballo, se fué. Que cho binéami ju aserihua. Todavía no está entrenado a ser montado. Asigá montando', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
('RD-000107', 'Así', 'Así', 'asi', NULL, 'Adv', 'Adv', 'También', '["También"]', '["Binoy upira así simiri. Su esposa también se fue."]', '[]', 'Binoy upira así simiri. Su esposa también se fue.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
('RD-000108', 'Asibá', 'Asibá', 'asiba', NULL, 'Imper', 'Imper', 'Siéntate', '["Siéntate"]', '["Mami risiri inaria, echo''ná ritérari moba asibá. Ya te cansaste de andar, siéntate allí sobre la piedra."]', '[]', 'Mami risiri inaria, echo''ná ritérari moba asibá. Ya te cansaste de andar, siéntate allí sobre la piedra.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
('RD-000109', 'Asiba', 'Asiba', 'asiba', NULL, 'Vi sing', 'Vi', 'Sentarse', '["Sentarse"]', '["Pachá asíbaga, huarú co''huari. Sentándose adentro, comió mucho. Echo''ná escuélachi asíbami rihuárini. Le ví sentado allí, en la escuela."]', '[]', 'Pachá asíbaga, huarú co''huari. Sentándose adentro, comió mucho. Echo''ná escuélachi asíbami rihuárini. Le ví sentado allí, en la escuela.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
('RD-000110', 'Asiba', 'Asiba', 'asiba', NULL, '', 'Sin clasificar', 'Quedarse (cosa)', '["Quedarse (cosa)"]', '["Echi huarú rité ripana jonsa cabótasa, huami ri’ré asíbari. Esa piedra rodó desde arriba y se quedó allí abajo. [pl.: muchiba] asináari vi quería sentarse"]', '["pl.: muchiba"]', 'Echi huarú rité ripana jonsa cabótasa, huami ri’ré asíbari. Esa piedra rodó desde arriba y se quedó allí abajo. [pl.: muchiba] asináari vi quería sentarse', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
('RD-000111', 'Asira', 'Asira', 'asira', NULL, 'Vi', 'Vi', 'Estar sentado (haciendo algo)', '["Estar sentado (haciendo algo)"]', '["Oserí ''nénia asírari. Estaba sentado leyendo."]', '[]', 'Oserí ''nénia asírari. Estaba sentado leyendo.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
