('RD-000119', 'Auché', 'Auché', 'auche', NULL, 'Adv', 'Adv', 'Otro', '["Otro"]', '["Auché baisá niráa, tres tantos. Auché biré, otro. Auché biréana, en otra parte. Auché biréara oméachi, el próximo domingo. Auché jaré, otros. Auché pe ocuá, otro poco. Auché siné, otra vez."]', '[]', 'Auché baisá niráa, tres tantos. Auché biré, otro. Auché biréana, en otra parte. Auché biréara oméachi, el próximo domingo. Auché jaré, otros. Auché pe ocuá, otro poco. Auché siné, otra vez.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 8, 'Transcrito'),
('RD-000120', 'Auchecho', 'Auchecho', 'auchecho', NULL, '', 'Sin clasificar', '', '[]', '["Auchecho siné, otra vez. Auchecho siné aní, repetir. Auchecho siné cu ‘ya, reponer."]', '[]', 'Auchecho siné, otra vez. Auchecho siné aní, repetir. Auchecho siné cu ‘ya, reponer.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 8, 9, 'Transcrito'),
('RD-000121', 'Ayá', 'Ayá', 'aya', NULL, '', 'Sin clasificar', 'Dando [Gerundio de ‘ya]', '["Dando [Gerundio de ‘ya]"]', '["Jena’í iyénari biré óhuami carúmati ohuáami ayá. Aquí andaba un médico dándonos medicinas de todas clases."]', '[]', 'Jena’í iyénari biré óhuami carúmati ohuáami ayá. Aquí andaba un médico dándonos medicinas de todas clases.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000122', 'A’yapi', 'A’yapi', 'a''yapi', NULL, '', 'Sin clasificar', 'Uno tras otro', '["Uno tras otro"]', '["Maparí nachútari sunú, a’yapi sísari echi pagótuami. Cuando hicieron distribución del maíz, la gente llegaba una tras otra."]', '[]', 'Maparí nachútari sunú, a’yapi sísari echi pagótuami. Cuando hicieron distribución del maíz, la gente llegaba una tras otra.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000123', 'Ayena', 'Ayena', 'ayena', NULL, 'Adv', 'Adv', 'Sí', '["Sí"]', '["¿Acha atí mujé onorá? Ayena, echo''ná pachá atí. ¿Está tu papá? Sí, está allí adentro."]', '[]', '¿Acha atí mujé onorá? Ayena, echo''ná pachá atí. ¿Está tu papá? Sí, está allí adentro.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000124', 'Ayena cho', 'Ayena cho', 'ayena cho', NULL, 'Adv', 'Adv', 'También, aún, sí', '["También, aún, sí"]', '["Ayena cho nayúnari echi jaré cúuchi. Aún los niños se enfermaron. Nijé onorá ayena cho nahuari. Mi papá también vino. Ayénasí, ayena así sí también."]', '[]', 'Ayena cho nayúnari echi jaré cúuchi. Aún los niños se enfermaron. Nijé onorá ayena cho nahuari. Mi papá también vino. Ayénasí, ayena así sí también.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000125', 'Ba''arí', 'Ba''arí', 'ba''ari', NULL, 'Adv', 'Adv', 'Mañana.', '["Mañana."]', '["Ba''arí bi''yá mañana temprano. Ba''arí piché hasta mañana"]', '[]', 'Ba''arí bi''yá mañana temprano. Ba''arí piché hasta mañana', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000126', 'Ba''arínara', 'Ba''arínara', 'ba''arinara', NULL, '', 'Sin clasificar', 'Al siguiente día (en el pasado) por la mañana', '["Al siguiente día (en el pasado) por la mañana"]', '["Maparí huarú quipari, ba''arínara huabé ruráari. Al día siguiente de la gran nevada hizo mucho frío."]', '[]', 'Maparí huarú quipari, ba''arínara huabé ruráari. Al día siguiente de la gran nevada hizo mucho frío.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000127', 'Bacá', 'Bacá', 'baca', NULL, 'S', 'S', 'Carrizo', '["Carrizo"]', '["Huaminá tu bacochi hue nirú bacá. Allá abajo, en el río, hay mucho carrizo. Echi jaré rarámuri echi bacá nihuá cuseri. Los tarahumaras hacen flautas del carrizo."]', '[]', 'Huaminá tu bacochi hue nirú bacá. Allá abajo, en el río, hay mucho carrizo. Echi jaré rarámuri echi bacá nihuá cuseri. Los tarahumaras hacen flautas del carrizo.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000128', 'Bacahuá', 'Bacahuá', 'bacahua', NULL, 'S', 'S', 'Hoja de la mazorca (seca)', '["Hoja de la mazorca (seca)"]', '["''Huisa, bacahuá napabusa, huaminánomí tamari nihuabo. En la pizca juntamos las hojas de las mazorcas; después haremos tamales."]', '[]', '''Huisa, bacahuá napabusa, huaminánomí tamari nihuabo. En la pizca juntamos las hojas de las mazorcas; después haremos tamales.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000129', 'Bacamú', 'Bacamú', 'bacamu', NULL, 'Vi', 'Vi', 'Infectarse (llaga), hincharse (con pus)', '["Infectarse (llaga), hincharse (con pus)"]', '["Chabé jonsa huabé cháanari, jipi ma bacamuri. Desde hace algún tiempo le salió un grano, ahora ya se hinchó con pus."]', '[]', 'Chabé jonsa huabé cháanari, jipi ma bacamuri. Desde hace algún tiempo le salió un grano, ahora ya se hinchó con pus.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000130', 'Bacánuhui', 'Bacánuhui', 'bacanuhui', NULL, 'S', 'S', 'Tipo de mata que crece en las barrancas. (ellos usan las raíces bien machucadas con un poco de agua para curarse cuando están "fuera de sí".).', '["Tipo de mata que crece en las barrancas. (ellos usan las raíces bien machucadas con un poco de agua para curarse cuando están \"fuera de sí\".)."]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000131', 'Bacarachi', 'Bacarachi', 'bacarachi', NULL, 'S', 'S', 'Tipo de víbora chica con rayas blancas', '["Tipo de víbora chica con rayas blancas"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000132', 'Bacarí', 'Bacarí', 'bacari', NULL, 'Vi', 'Vi', 'Tener enfermedad venérea', '["Tener enfermedad venérea"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000133', 'Bacó', 'Bacó', 'baco', NULL, 'Vi', 'Vi', 'Ponerse amarillo (las matas de maíz por haber llovido)', '["Ponerse amarillo (las matas de maíz por haber llovido)"]', '["Chabé biréara michá huarú ucuri sinibí rahué, echijiti pachí ma bacori. Hace un mes llovió mucho todos los días, por eso las matas de maíz se pusieron amarillas."]', '[]', 'Chabé biréara michá huarú ucuri sinibí rahué, echijiti pachí ma bacori. Hace un mes llovió mucho todos los días, por eso las matas de maíz se pusieron amarillas.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 9, 9, 'Transcrito'),
('RD-000134', 'Bacochi', 'Bacochi', 'bacochi', NULL, 'S', 'S', 'Río', '["Río"]', '["Huamina ri''reti urí, huabé ri''ré bacochi ju. Allá en el fondo de la barranca, muy abajo, está el río."]', '[]', 'Huamina ri''reti urí, huabé ri''ré bacochi ju. Allá en el fondo de la barranca, muy abajo, está el río.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000135', 'Bacúi', 'Bacúi', 'bacui', NULL, 'S', 'S', 'Otate', '["Otate"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
