('RD-000137', 'Bacha', '1Bacha', 'bacha', 1, 'Adv', 'Adv', 'Primeramente, adelante, enfrente', '["Primeramente, adelante, enfrente"]', '["Mapari mitebo biré oco, bachá niráa chutabo echi ripurá. Cuando tumbamos un pino, primeramente amolamos el hacha. Bachá huiríami, primogénito. Bachá niráa, de antemano. Bachá simí, avanza, precede"]', '[]', 'Mapari mitebo biré oco, bachá niráa chutabo echi ripurá. Cuando tumbamos un pino, primeramente amolamos el hacha. Bachá huiríami, primogénito. Bachá niráa, de antemano. Bachá simí, avanza, precede', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000138', 'Bachá', '2Bachá', 'bacha', 2, 'Vipl', 'Vi', 'Meter (a la cárcel), poner (adentro)', '["Meter (a la cárcel), poner (adentro)"]', '["[pp.: bachárami] Bachánari. Quisieron ponerlo preso. Bachara asari, estaba preso, estaba encerrado"]', '["pp.: bachárami"]', '[pp.: bachárami] Bachánari. Quisieron ponerlo preso. Bachara asari, estaba preso, estaba encerrado', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000139', 'Bacháami', 'Bacháami', 'bachaami', NULL, 'Adv', 'Adv', 'Ante, delante, por delante, enfrente de', '["Ante, delante, por delante, enfrente de"]', '["Bacháami echi siríami yuhua huiribámani. Voy a comparecer delante del gobernador. Bacháami huiriami aparecer delante de, comparecer. Bacháami jaba comparecen."]', '[]', 'Bacháami echi siríami yuhua huiribámani. Voy a comparecer delante del gobernador. Bacháami huiriami aparecer delante de, comparecer. Bacháami jaba comparecen.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
