('RD-000142', 'Bachahuara', 'Bachahuara', 'bachahuara', NULL, 'Vi', 'Vi', 'Ir adelante.', '["Ir adelante."]', '["Bachahuárari ichayá. Se apuró a sembrar primero. (lit.: adelante sembró) Nijeni hue jiyahua, echijiti bachahuáramani. Tengo mucha prisa; por eso voy adelante."]', '[]', 'Bachahuárari ichayá. Se apuró a sembrar primero. (lit.: adelante sembró) Nijeni hue jiyahua, echijiti bachahuáramani. Tengo mucha prisa; por eso voy adelante.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000143', 'Bachari', 'Bachari', 'bachari', NULL, 'Vt', 'Vt', 'Pret hacer preso', '["Pret hacer preso"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000144', 'Baché', 'Baché', 'bache', NULL, 'Vi', 'Vi', 'Apuntar bien jugando cuatro (tirando al hoyo)', '["Apuntar bien jugando cuatro (tirando al hoyo)"]', '["¡Gará baché! ¡Apúntelo bien!"]', '[]', '¡Gará baché! ¡Apúntelo bien!', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000145', 'Bachéi', 'Bachéi', 'bachei', NULL, 'Vi', 'Vi', 'Tener hermano mayor', '["Tener hermano mayor"]', '["Nijeni quetasi bachéi, mapujiti nijé binoy bachá huiríami ju. No tengo hermano mayor, porque yo soy el primero."]', '[]', 'Nijeni quetasi bachéi, mapujiti nijé binoy bachá huiríami ju. No tengo hermano mayor, porque yo soy el primero.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000146', 'Bachi', '1Bachi', 'bachi', 1, 'S', 'S', 'Hermano mayor', '["Hermano mayor"]', '["Nijeni bachirúami ju, mapujítini bachá ochérami ju. Yo soy el primogénito, porque nací primero. Nijé bachirá mi hermano mayor."]', '[]', 'Nijeni bachirúami ju, mapujítini bachá ochérami ju. Yo soy el primogénito, porque nací primero. Nijé bachirá mi hermano mayor.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000147', 'Bachi', '2Bachi', 'bachi', 2, 'S', 'S', 'Calabaza.', '["Calabaza."]', '["Bachí sihuará, flor de calabaza"]', '[]', 'Bachí sihuará, flor de calabaza', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000148', 'Bachima', 'Bachima', 'bachima', NULL, 'Vt', 'Vt', 'Rociar', '["Rociar"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000149', 'Bachirúami', 'Bachirúami', 'bachiruami', NULL, 'Adj', 'Adj', 'Primogénito, hermano mayor', '["Primogénito, hermano mayor"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000150', 'Ba''hué', 'Ba''hué', 'ba''hue', NULL, 'Vi', 'Vi', 'Hay agua', '["Hay agua"]', '["Echo''ná huabé huaquichéami ju, quetasi ba''hué. Allí está muy seco, no hay agua. [pret.: ba''huéari; fut.: ba''huérama]"]', '["pret.: ba''huéari; fut.: ba''huérama"]', 'Echo''ná huabé huaquichéami ju, quetasi ba''hué. Allí está muy seco, no hay agua. [pret.: ba''huéari; fut.: ba''huérama]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 10, 'Transcrito'),
('RD-000151', 'Ba''huí', 'Ba''huí', 'ba''hui', NULL, 'S', 'S', 'Agua', '["Agua"]', '["Ba''huí túmani. Voy a traer agua. Ba''huí bají toma agua. Ba''huí huichirachi cascada. Ba''huí machina mana agua (p.ej.: de manantial). Ba''huí ro''hué riega. Ba''huí tuma trae agua. Huasí ba''huira jugo de fruta. Ba''huichí vi caer el sereno Jipi ma bará ju. Sinibí rahué bi''yá hue ba''huichí. Ahora es el tiempo de aguas. Todos los días, temprano, cae mucho sereno."]', '[]', 'Ba''huí túmani. Voy a traer agua. Ba''huí bají toma agua. Ba''huí huichirachi cascada. Ba''huí machina mana agua (p.ej.: de manantial). Ba''huí ro''hué riega. Ba''huí tuma trae agua. Huasí ba''huira jugo de fruta. Ba''huichí vi caer el sereno Jipi ma bará ju. Sinibí rahué bi''yá hue ba''huichí. Ahora es el tiempo de aguas. Todos los días, temprano, cae mucho sereno.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 10, 11, 'Transcrito'),
('RD-000152', 'Bahuirá', 'Bahuirá', 'bahuira', NULL, 'Vt', 'Vt', 'Herrar', '["Herrar"]', '["Ma bahuirabo echi huáasi, mapujiti nijé bucura ju. Ya vamos a herrar esa vaca,porque es mía."]', '[]', 'Ma bahuirabo echi huáasi, mapujiti nijé bucura ju. Ya vamos a herrar esa vaca,porque es mía.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000153', 'Ba''huira', 'Ba''huira', 'ba''huira', NULL, 'S', 'S', 'Jugo, caldo', '["Jugo, caldo"]', '["Je''ná masana hue huaquichéami ju. Tasi te ba''huira. Esta manzana está muy seca. No tiene jugo. Masana ba''huira jugo de manzana."]', '[]', 'Je''ná masana hue huaquichéami ju. Tasi te ba''huira. Esta manzana está muy seca. No tiene jugo. Masana ba''huira jugo de manzana.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000154', 'Ba''huirá', 'Ba''huirá', 'ba''huira', NULL, 'Vi', 'Vi', 'Hacer caldo, echar agua a un líquido', '["Hacer caldo, echar agua a un líquido"]', '["Co''orí hue ba''huirari. Echó mucha agua al esquiate."]', '[]', 'Co''orí hue ba''huirari. Echó mucha agua al esquiate.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000155', 'Baisá', 'Baisá', 'baisa', NULL, 'Adv', 'Adv', 'Tercero', '["Tercero"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000156', 'Baisá macoy', 'Baisá macoy', 'baisa macoy', NULL, 'Adj', 'Adj', 'Treinta', '["Treinta"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000157', 'Bajácami', 'Bajácami', 'bajacami', NULL, 'Pp', 'Pp', 'Hinchado', '["Hinchado"]', '["Huarú bajácami ju ramichí; ne huabé ocorá. Tengo muy hinchada la encía, porque la muela me duele mucho."]', '[]', 'Huarú bajácami ju ramichí; ne huabé ocorá. Tengo muy hinchada la encía, porque la muela me duele mucho.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000158', 'Bají', 'Bají', 'baji', NULL, 'Vi', 'Vi', 'Tomar, beber (tesgüino, agua)', '["Tomar, beber (tesgüino, agua)"]', '["Echo''ná huarú maní suguí. Ba''arí bajima huareco. Allí hay mucho tesgüino. Tal vez van a tomar mañana. Bajimani ba''huí. Voy a tomar agua."]', '[]', 'Echo''ná huarú maní suguí. Ba''arí bajima huareco. Allí hay mucho tesgüino. Tal vez van a tomar mañana. Bajimani ba''huí. Voy a tomar agua.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000159', 'Bajíami', 'Bajíami', 'bajiami', NULL, 'S', 'S', 'Curandero (que toma tesgüino)', '["Curandero (que toma tesgüino)"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000160', 'Bajíbachami', 'Bajíbachami', 'bajibachami', NULL, 'Pp', 'Pp', 'Hinchado por desnutrición', '["Hinchado por desnutrición"]', '["Echi tohui bajíbachami ju. Ne buchuhuí bajínari. Ese niño está hinchado por desnutrición. Se le hinchó todo el cuerpo."]', '[]', 'Echi tohui bajíbachami ju. Ne buchuhuí bajínari. Ese niño está hinchado por desnutrición. Se le hinchó todo el cuerpo.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000161', 'Bajichahua', 'Bajichahua', 'bajichahua', NULL, 'Vi', 'Vi', 'Hacer norte (viento frío del norte)', '["Hacer norte (viento frío del norte)"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000162', 'Bajicháhuari', 'Bajicháhuari', 'bajichahuari', NULL, 'S', 'S', 'Norte (viento frío del norte)', '["Norte (viento frío del norte)"]', '["Jipi ne huabé simírami ruráami icá. Hue bajicháhuari ju. Ahora está muy helado el aire. Es un norte."]', '[]', 'Jipi ne huabé simírami ruráami icá. Hue bajicháhuari ju. Ahora está muy helado el aire. Es un norte.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000163', 'Bajichi', 'Bajichi', 'bajichi', NULL, 'S', 'S', 'Pozo, ojo de agua, manantial.', '["Pozo, ojo de agua, manantial."]', '["Chabénara huaminá huaquicheri echo''ná bajichi; chopi jipi auchecho cu bajítari mapujiti ma gará ucú. Hace tiempo se secó allí donde salió agua; pero ya sale otra vez porque llueve bastante ahora."]', '[]', 'Chabénara huaminá huaquicheri echo''ná bajichi; chopi jipi auchecho cu bajítari mapujiti ma gará ucú. Hace tiempo se secó allí donde salió agua; pero ya sale otra vez porque llueve bastante ahora.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000164', 'Bajíhuachi', 'Bajíhuachi', 'bajihuachi', NULL, 'S', 'S', 'Tiempo de tomar tesgüino', '["Tiempo de tomar tesgüino"]', '["Suguí bajíhuachi jaré rarámuri huabé nacohua. Algunos tarahumaras pelean mucho cuando es tiempo de tomar tesgüino."]', '[]', 'Suguí bajíhuachi jaré rarámuri huabé nacohua. Algunos tarahumaras pelean mucho cuando es tiempo de tomar tesgüino.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 11, 11, 'Transcrito'),
('RD-000165', 'Bajíhuami', 'Bajíhuami', 'bajihuami', NULL, 'Adj', 'Adj', 'Potable (bebida)', '["Potable (bebida)"]', '["¿Acha bajíhuami ju? ¿Se puede tomar? (es potable). Ba''huí bajíhuami agua potable."]', '[]', '¿Acha bajíhuami ju? ¿Se puede tomar? (es potable). Ba''huí bajíhuami agua potable.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000166', 'Bajina', 'Bajina', 'bajina', NULL, 'Vi', 'Vi', 'Hincharse.', '["Hincharse."]', '["Hue ocorá ramichí, huarú bajínari nijé banarachi. Me duele mucho la muela, y se me hinchó mucho la mejilla. [pret.: bajínari; fut.: bajínama]"]', '["pret.: bajínari; fut.: bajínama"]', 'Hue ocorá ramichí, huarú bajínari nijé banarachi. Me duele mucho la muela, y se me hinchó mucho la mejilla. [pret.: bajínari; fut.: bajínama]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000167', 'Bajira', 'Bajira', 'bajira', NULL, 'Vt', 'Vt', 'Hacer tomar o beber.', '["Hacer tomar o beber."]', '["Nijeni quetasi naquiri bajínara, chopi jaré rijoy tamí bajírari. Yo no quería tomar tesgüino, pero algunos hombres me hicieron tomarlo a la fuerza."]', '[]', 'Nijeni quetasi naquiri bajínara, chopi jaré rijoy tamí bajírari. Yo no quería tomar tesgüino, pero algunos hombres me hicieron tomarlo a la fuerza.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000168', 'Bajita', 'Bajita', 'bajita', NULL, 'Vi', 'Vi', 'Salir agua', '["Salir agua"]', '["[pret.: bajítari; fut.: bajítama]"]', '["pret.: bajítari; fut.: bajítama"]', '[pret.: bajítari; fut.: bajítama]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000169', 'Bajuhua', 'Bajuhua', 'bajuhua', NULL, 'Vi', 'Vi', 'Ir a la tesgüinada (a tomar)', '["Ir a la tesgüinada (a tomar)"]', '["Echi rijoy hue ra''iri suguí, echijiti ma simea bajuhua. A ese hombre le gusta mucho e l tesgüino; por eso se irá a l a tesgüinada."]', '[]', 'Echi rijoy hue ra''iri suguí, echijiti ma simea bajuhua. A ese hombre le gusta mucho e l tesgüino; por eso se irá a l a tesgüinada.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000170', 'Bajuré', 'Bajuré', 'bajure', NULL, 'Vi', 'Vi', 'Invitar a la casa o al trabajo (a tomar tesgüino)', '["Invitar a la casa o al trabajo (a tomar tesgüino)"]', '["Jaré rarámuri huicabé bajuresa nochara. Algunos tarahumaras invitan a muchos a tomar tesgüino, pero los ponen a trabajar antes."]', '[]', 'Jaré rarámuri huicabé bajuresa nochara. Algunos tarahumaras invitan a muchos a tomar tesgüino, pero los ponen a trabajar antes.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000171', 'Bajurí', 'Bajurí', 'bajuri', NULL, 'S', 'S', 'Nutria', '["Nutria"]', '["Echi bajurí biré namuti ju, ri''ré ba''huichí iyénami. La nutria es un animal que puede nadar en el agua."]', '[]', 'Echi bajurí biré namuti ju, ri''ré ba''huichí iyénami. La nutria es un animal que puede nadar en el agua.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000172', 'Bamiba', 'Bamiba', 'bamiba', NULL, 'Vi', 'Vi', 'Hacer un año', '["Hacer un año"]', '["Ma biré bamiba maparí mucuri nijé onorá. Ya hace un año que murió mi papá."]', '[]', 'Ma biré bamiba maparí mucuri nijé onorá. Ya hace un año que murió mi papá.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000173', 'Bamíbari', 'Bamíbari', 'bamibari', NULL, 'S', 'S', 'Año', '["Año"]', '["Huicabé bamíbani. Chabé bamíbari. El año pasado. Chabé biquiyá bamíbari. El año pasado."]', '[]', 'Huicabé bamíbani. Chabé bamíbari. El año pasado. Chabé biquiyá bamíbari. El año pasado.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000174', 'Baná', 'Baná', 'bana', NULL, 'S', 'S', 'Mejilla', '["Mejilla"]', '["Tamí banarachi cho''nari. Me pegó en la mejilla. Banachí en la mejilla. Nijé banará. Mi mejilla."]', '[]', 'Tamí banarachi cho''nari. Me pegó en la mejilla. Banachí en la mejilla. Nijé banará. Mi mejilla.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000175', 'Banagá', 'Banagá', 'banaga', NULL, 'S', 'S', 'Lama, moho', '["Lama, moho"]', '["Ba''huí hue banagué. Hay mucha lama en el agua. Jipi hue nirú banagá echo''ná comichi. Ahora hay mucha lama allí, en el arroyo. Banagué vi hay lama."]', '[]', 'Ba''huí hue banagué. Hay mucha lama en el agua. Jipi hue nirú banagá echo''ná comichi. Ahora hay mucha lama allí, en el arroyo. Banagué vi hay lama.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000176', 'Banásani', 'Banásani', 'banasani', NULL, 'S', 'S', 'Víbora venenosa de menos de un metro, un poco negra, que no tiene cascabel, y vive en la barranca.', '["Víbora venenosa de menos de un metro, un poco negra, que no tiene cascabel, y vive en la barranca."]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000177', 'Bané', 'Bané', 'bane', NULL, 'Vi', 'Vi', 'Tener mejillas.', '["Tener mejillas."]', '["O''huari banéami ju. Tiene mejillas gordas. Banéami pp que tiene mejillas"]', '[]', 'O''huari banéami ju. Tiene mejillas gordas. Banéami pp que tiene mejillas', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000178', 'Ba''nésara', 'Ba''nésara', 'ba''nesara', NULL, 'Vi', 'Vi', 'Gastarse la cobija', '["Gastarse la cobija"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000179', 'Ba''nésuri', 'Ba''nésuri', 'ba''nesuri', NULL, 'S', 'S', 'Una cobija gastada.', '["Una cobija gastada."]', '["Nijé quimara ma ba''nésuri ju. Mi cobija ya está gastada."]', '[]', 'Nijé quimara ma ba''nésuri ju. Mi cobija ya está gastada.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 12, 12, 'Transcrito'),
('RD-000180', 'Banihuá', 'Banihuá', 'banihua', NULL, 'S', 'S', 'Cierta hierba que produce semillas manchadas de rojo y negro. Las muelen con agua y se ponen en una hueja cerca de la cruz cuando bailan matachines. Lo rocían sobre las chivas para curarlas, y para protegerlas contra las enfermedades.', '["Cierta hierba que produce semillas manchadas de rojo y negro. Las muelen con agua y se ponen en una hueja cerca de la cruz cuando bailan matachines. Lo rocían sobre las chivas para curarlas, y para protegerlas contra las enfermedades."]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 13, 13, 'Transcrito'),
('RD-000181', 'Banihuí', 'Banihuí', 'banihui', NULL, 'Vi', 'Vi', 'Crecer larga y enredada (mata)', '["Crecer larga y enredada (mata)"]', '["I''huéari banihuiri bachí. Creció larga la mata de calabaza."]', '[]', 'I''huéari banihuiri bachí. Creció larga la mata de calabaza.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 13, 13, 'Transcrito'),
('RD-000182', 'Banira', 'Banira', 'banira', NULL, 'Vt', 'Vt', 'Arrastrar, llevar (jalando con mecate).', '["Arrastrar, llevar (jalando con mecate)."]', '["Huíiga baníramani cahué. Voy a llevar el caballo jalandolo. Rojuá baníraga ipó achámani. Arrastrando ramas de encino, voy a echarlas en el barbecho para quemarlas ahí. [pret.: banírari; fut.: banírama, banagá]"]', '["pret.: banírari; fut.: banírama, banagá"]', 'Huíiga baníramani cahué. Voy a llevar el caballo jalandolo. Rojuá baníraga ipó achámani. Arrastrando ramas de encino, voy a echarlas en el barbecho para quemarlas ahí. [pret.: banírari; fut.: banírama, banagá]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 13, 13, 'Transcrito'),
('RD-000183', 'Banisú', 'Banisú', 'banisu', NULL, 'Vt', 'Vt', 'Jalar (estirando)', '["Jalar (estirando)"]', '["Nijeni que omérari banisúhua echi cahué mapujiti hue aparú. No pude jalar ese caballo, porque está muy bravo."]', '[]', 'Nijeni que omérari banisúhua echi cahué mapujiti hue aparú. No pude jalar ese caballo, porque está muy bravo.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 13, 13, 'Transcrito'),
('RD-000184', 'Bapá', 'Bapá', 'bapa', NULL, 'Vt', 'Vt', 'Apedrear', '["Apedrear"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 13, 13, 'Transcrito'),
('RD-000185', 'Baquí', 'Baquí', 'baqui', NULL, 'Vi', 'Vi', 'Entrar (solo)', '["Entrar (solo)"]', '["Echi binériami ma baquiri pachá escuélachi, chopi echi jaré cúrohui que cho mo''huiri. El maestro ya entró a la escuela; pero los niños no han entrado todavía. [fut.: baquiméa; pl.: mo''hui]"]', '["fut.: baquiméa; pl.: mo''hui"]', 'Echi binériami ma baquiri pachá escuélachi, chopi echi jaré cúrohui que cho mo''huiri. El maestro ya entró a la escuela; pero los niños no han entrado todavía. [fut.: baquiméa; pl.: mo''hui]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 13, 13, 'Transcrito'),
('RD-000186', 'Baquirini', 'Baquirini', 'baquirini', NULL, 'S', 'S', 'Padrino, madrina', '["Padrino, madrina"]', '["Echi rijoy nijé baquirínahuara ju. Échico tamí rihuarari. Ese hombre es mi padrino. El me puso mi nombre. Nijé baquirínahuara, mi padrino, mi madrina."]', '[]', 'Echi rijoy nijé baquirínahuara ju. Échico tamí rihuarari. Ese hombre es mi padrino. El me puso mi nombre. Nijé baquirínahuara, mi padrino, mi madrina.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 13, 13, 'Transcrito'),
('RD-000187', 'Bará', 'Bará', 'bara', NULL, 'S', 'S', 'El tiempo de lluvias', '["El tiempo de lluvias"]', '["Jipi ma bará ju; hue nirú pachí. Ya es tiempo de lluvias; hay muchos elotes. Que ''me ayó barásama. Pronto llegará el tiempo de lluvias."]', '[]', 'Jipi ma bará ju; hue nirú pachí. Ya es tiempo de lluvias; hay muchos elotes. Que ''me ayó barásama. Pronto llegará el tiempo de lluvias.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 13, 13, 'Transcrito'),
