('RD-000190', 'Barami', 'Barami', 'barami', NULL, 'Vi', 'Vi', 'Tener sed', '["Tener sed"]', '["Huabeni barami, mapujiti quetasi te ba''huí. Tengo mucha sed, porque no hay agua. [fut.: barámama]"]', '["fut.: barámama"]', 'Huabeni barami, mapujiti quetasi te ba''huí. Tengo mucha sed, porque no hay agua. [fut.: barámama]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 13, 13, 'Transcrito'),
