('RD-000280', 'Bité', '1Bité', 'bite', 1, 'Vi', 'Vi', 'Sing habitar, morar, vivir', '["Sing habitar, morar, vivir"]', '["¿Cumi bité?, ¿Dónde vives? Echo''ná basigóchi ni bité. Vivo allí, en Basigochi. [pret.: bitéeri; fut.: bitérama; pl.: piré]"]', '["pret.: bitéeri; fut.: bitérama; pl.: piré"]', '¿Cumi bité?, ¿Dónde vives? Echo''ná basigóchi ni bité. Vivo allí, en Basigochi. [pret.: bitéeri; fut.: bitérama; pl.: piré]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 17, 18, 'Transcrito'),
('RD-000281', 'Bité', '2Bité', 'bite', 2, 'Vi', 'Vi', 'Estar pesado', '["Estar pesado"]', '["Ne huabé bité, quetásini omero o''huicha. Está muy pesado. No puedo levantarlo. [pret.: bitéari; fut.: bitítama]"]', '["pret.: bitéari; fut.: bitítama"]', 'Ne huabé bité, quetásini omero o''huicha. Está muy pesado. No puedo levantarlo. [pret.: bitéari; fut.: bitítama]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000282', 'Bitéami', 'Bitéami', 'biteami', NULL, 'Adj sin', 'Adj', 'Morador, que vive', '["Morador, que vive"]', '["Echi rijoy jena''í samichí bitéami ju. Ese hombre vive aquí en samachique. Huanihuí jena''í piréami napahuima. Pasado mañana se juntarán los que viven aquí. [pl.: piréami]"]', '["pl.: piréami"]', 'Echi rijoy jena''í samichí bitéami ju. Ese hombre vive aquí en samachique. Huanihuí jena''í piréami napahuima. Pasado mañana se juntarán los que viven aquí. [pl.: piréami]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000283', 'Biteba', 'Biteba', 'biteba', NULL, 'Vi', 'Vi', 'Pasar la noche, pernoctar', '["Pasar la noche, pernoctar"]', '["Echo''ná cahuichí bitébari. Allí, en el campo, pasó la noche. [fut.: bitebama] Véase chi''reba"]', '["fut.: bitebama"]', 'Echo''ná cahuichí bitébari. Allí, en el campo, pasó la noche. [fut.: bitebama] Véase chi''reba', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000284', 'Bitechi', 'Bitechi', 'bitechi', NULL, 'S', 'S', 'Casa', '["Casa"]', '["Nijé bitérachi, mi casa. Queni bitechi, mi casa"]', '[]', 'Nijé bitérachi, mi casa. Queni bitechi, mi casa', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000285', 'Bití', 'Bití', 'biti', NULL, 'Vi pl', 'Vi', 'Estar acostados (varios)', '["Estar acostados (varios)"]', '["Ri''ré huichí bitir, se acostaron en la tierra. Hui''rique rocogó bitíbari cochiboa, ya muy de noche se acostaron a dormir. [sing.: bu''huí; fut.: bitimea]. Bitibama, se acostarán. Bitisí ¡acuéstense!"]', '["sing.: bu''huí; fut.: bitimea"]', 'Ri''ré huichí bitir, se acostaron en la tierra. Hui''rique rocogó bitíbari cochiboa, ya muy de noche se acostaron a dormir. [sing.: bu''huí; fut.: bitimea]. Bitibama, se acostarán. Bitisí ¡acuéstense!', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000286', 'Bitiba', 'Bitiba', 'bitiba', NULL, 'Vi', 'Vi', 'Echarse (animales), están acostándose', '["Echarse (animales), están acostándose"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000287', 'Bitichí', 'Bitichí', 'bitichi', NULL, 'S', 'S', 'Casa, habitación', '["Casa, habitación"]', '["Echo''ná bitichí iyénasí simiri, iba hacia la casa."]', '[]', 'Echo''ná bitichí iyénasí simiri, iba hacia la casa.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000288', 'Bitira', 'Bitira', 'bitira', NULL, 'Vi', 'Vi', 'Andar (como borracho)', '["Andar (como borracho)"]', '["Capilata bitira, se revuelve (el caballo). Bitíra,echarse (de un lado al otro)."]', '[]', 'Capilata bitira, se revuelve (el caballo). Bitíra,echarse (de un lado al otro).', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000289', 'Bitórata', 'Bitórata', 'bitorata', NULL, 'Vt', 'Vt', 'Hacer cajetes', '["Hacer cajetes"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000290', 'Bitori', 'Bitori', 'bitori', NULL, 'S', 'S', 'Cajete, plato, cazuela', '["Cajete, plato, cazuela"]', '["Bitórachi, en el cajete"]', '[]', 'Bitórachi, en el cajete', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000291', 'Bi''yá', 'Bi''yá', 'bi''ya', NULL, 'Adv', 'Adv', 'Temprano', '["Temprano"]', '["Bi''yá rocogó, en la madrugada. Bi''yá chónachi, temprano (todavía está obscuro). Bi''yábijí, hoy temprano (todavía). Biyá chi''rásiachi, madrugada."]', '[]', 'Bi''yá rocogó, en la madrugada. Bi''yá chónachi, temprano (todavía está obscuro). Bi''yábijí, hoy temprano (todavía). Biyá chi''rásiachi, madrugada.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000292', 'Bocohuí', 'Bocohuí', 'bocohui', NULL, 'Vi', 'Vi', 'Ocultarse, ponerse el sol', '["Ocultarse, ponerse el sol"]', '["Ma bocohuiri rayénari. Ya se puso el sol."]', '[]', 'Ma bocohuiri rayénari. Ya se puso el sol.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000293', 'Bocuirachi', 'Bocuirachi', 'bocuirachi', NULL, 'S', 'S', 'Cascada, salto de agua', '["Cascada, salto de agua"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
