('RD-000295', 'Bo''huá', 'Bo''huá', 'bo''hua', NULL, 'S', 'S', 'Oveja, borrego', '["Oveja, borrego"]', '["Bo''huá bo''huara, lana de borrego."]', '[]', 'Bo''huá bo''huara, lana de borrego.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000296', 'Bo''hué', 'Bo''hué', 'bo''hue', NULL, 'Vi', 'Vi', 'Tener lana, pelo', '["Tener lana, pelo"]', '["Hue bo''huéami ju echi bo''huá, ma siquiboa. Tiene mucha lana ese borrego; vamos a trasquilarlo. Pp.: bo''huéamil."]', '[]', 'Hue bo''huéami ju echi bo''huá, ma siquiboa. Tiene mucha lana ese borrego; vamos a trasquilarlo. Pp.: bo''huéamil.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000297', 'Bo''huí', 'Bo''huí', 'bo''hui', NULL, 'Vi', 'Vi', 'Postrarse', '["Postrarse"]', '[]', '[]', '', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000298', 'Bóisi', 'Bóisi', 'boisi', NULL, 'S', 'S', 'Buey', '["Buey"]', '["[pl.: ibóisi]"]', '["pl.: ibóisi"]', '[pl.: ibóisi]', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 18, 'Transcrito'),
('RD-000299', 'Boioní', 'Boioní', 'boioni', NULL, 'Vi', 'Vi', 'Pasar a pie al otro lado del agua, vadear', '["Pasar a pie al otro lado del agua, vadear"]', '["Maparí huabé bu''huíbari ba''huí, nijeni arigá boioniri. Cuando estaba muy crecida el agua, yo siempre pasaba al otro lado vadeando."]', '[]', 'Maparí huabé bu''huíbari ba''huí, nijeni arigá boioniri. Cuando estaba muy crecida el agua, yo siempre pasaba al otro lado vadeando.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 18, 19, 'Transcrito'),
('RD-000300', 'Bo''ná', 'Bo''ná', 'bo''na', NULL, 'Vt', 'Vt', 'Arrancar, desherbar', '["Arrancar, desherbar"]', '["O''huari ochérari mocuásari, ma cáraga bo''niboa. Creció mucho la hierba, ya vamos a arrancarla. [fut.: bo nomea]. Bo''nisí ¡arráncalos!"]', '["fut.: bo nomea"]', 'O''huari ochérari mocuásari, ma cáraga bo''niboa. Creció mucho la hierba, ya vamos a arrancarla. [fut.: bo nomea]. Bo''nisí ¡arráncalos!', 'SRC-02', 'DICCIONARIO raramuri.pdf', 19, 19, 'Transcrito');--> statement-breakpoint
