('RD-000311', 'Boriba', 'Boriba', 'boriba', NULL, 'Vi', 'Vi', 'Correr el agua (en una corriente)', '["Correr el agua (en una corriente)"]', '["Maparí huarú bu''huíbari ba''huí, ne huabé boríbari. Cuando creció mucho el arroyo, corrió mucha agua."]', '[]', 'Maparí huarú bu''huíbari ba''huí, ne huabé boríbari. Cuando creció mucho el arroyo, corrió mucha agua.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 19, 19, 'Transcrito'),
('RD-000312', 'Borogá', 'Borogá', 'boroga', NULL, 'Pp', 'Pp', 'Amarrado', '["Amarrado"]', '["Huíiti borogá cu tori. Amarrado con mecate, lo llevó. Borogá tobóa. Vamos a llevarlo amarrado. Véase buré"]', '[]', 'Huíiti borogá cu tori. Amarrado con mecate, lo llevó. Borogá tobóa. Vamos a llevarlo amarrado. Véase buré', 'SRC-02', 'DICCIONARIO raramuri.pdf', 19, 19, 'Transcrito'),
