('RD-000321', 'Bucura', 'Bucura', 'bucura', NULL, 'Adj', 'Adj', 'Poseedor (de un animal)', '["Poseedor (de un animal)"]', '["Nijé bucura cahué ju. Es mi caballo. ¿Chigá bucura ju? ¿Quién es el dueño? (del animal). Si''nu bucura, bestia ajena."]', '[]', 'Nijé bucura cahué ju. Es mi caballo. ¿Chigá bucura ju? ¿Quién es el dueño? (del animal). Si''nu bucura, bestia ajena.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 19, 20, 'Transcrito'),
('RD-000322', 'Bucurí', 'Bucurí', 'bucuri', NULL, 'Adv', 'Adv', 'Hace poco, nuevamente, hace rato', '["Hace poco, nuevamente, hace rato"]', '["Bucurí cu nahuari. Hace poco volvió. Bucuripi, hace poquito, hace ratito. Bucurí, nihuá renueva. Bucurí nihuárami, recién hecho. Bucurí simíri, apenas salió."]', '[]', 'Bucurí cu nahuari. Hace poco volvió. Bucuripi, hace poquito, hace ratito. Bucurí, nihuá renueva. Bucurí nihuárami, recién hecho. Bucurí simíri, apenas salió.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 20, 20, 'Transcrito'),
('RD-000323', 'Buchí', 'Buchí', 'buchi', NULL, 'Vi', 'Vi', 'Contener', '["Contener"]', '["Ocuá litro buchí. Contiene dos litros."]', '[]', 'Ocuá litro buchí. Contiene dos litros.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 20, 20, 'Transcrito'),
