('RD-001009', 'Hui´ré', 'Hui´ré', 'hui´re', NULL, 'Vi', 'Vi', 'Tener aretes', '["Tener aretes"]', '["Echi moquí hue semati huir’e. Esa mujer tiene aretes muy bonitos."]', '[]', 'Echi moquí hue semati huir’e. Esa mujer tiene aretes muy bonitos.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 47, 47, 'Transcrito'),
('RD-001010', 'Huirá', 'Huirá', 'huira', NULL, 'Vt', 'Vt', '1. Parar 2. Elegir, nombrar a una autoridad', '["Parar","Elegir, nombrar a una autoridad"]', '["Echo’ná sitochi huirari ripurá. Puso parada el hacha, en el rincón. Tamí huirábari capitani niráa. Me eligieron como capitán. [pl.: jahua; pret.: huirásari]."]', '["pl.: jahua; pret.: huirásari"]', 'Echo’ná sitochi huirari ripurá. Puso parada el hacha, en el rincón. Tamí huirábari capitani niráa. Me eligieron como capitán. [pl.: jahua; pret.: huirásari].', 'SRC-02', 'DICCIONARIO raramuri.pdf', 47, 48, 'Transcrito'),
('RD-001011', 'Huiráami', 'Huiráami', 'huiraami', NULL, 'S sing', 'S', 'Vieja, anciana', '["Vieja, anciana"]', '["[pl.: ‘huécami]."]', '["pl.: ‘huécami"]', '[pl.: ‘huécami].', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
('RD-001012', 'Huiraba', 'Huiraba', 'huiraba', NULL, 'Vt', 'Vt', 'Parar (detener)', '["Parar (detener)"]', '["Nijeni huirábama echi motor. Boy a parar el motor. [pret.: huirábari]."]', '["pret.: huirábari"]', 'Nijeni huirábama echi motor. Boy a parar el motor. [pret.: huirábari].', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
('RD-001013', 'Huirara', 'Huirara', 'huirara', NULL, 'Vi', 'Vi', 'Envejecerse (mujer)', '["Envejecerse (mujer)"]', '["Echi muquí ma hue huirárari. Esa mujer se ha envejecido mucho."]', '[]', 'Echi muquí ma hue huirárari. Esa mujer se ha envejecido mucho.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
('RD-001014', 'Huirárasi', 'Huirárasi', 'huirarasi', NULL, '', 'Sin clasificar', 'Levantar, parar (poste, persona)', '["Levantar, parar (poste, persona)"]', '["[pret. de huirá]."]', '["pret. de huirá"]', '[pret. de huirá].', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
('RD-001015', 'Hui’ré', 'Hui’ré', 'hui''re', NULL, 'Adj', 'Adj', 'Ancho', '["Ancho"]', '["Hui’ré inaro ba’huí. Está ancho el río. Hui’ré ichiméani. Voy a sembrar ancho (mucho)."]', '[]', 'Hui’ré inaro ba’huí. Está ancho el río. Hui’ré ichiméani. Voy a sembrar ancho (mucho).', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
('RD-001016', 'Hui’rí', 'Hui’rí', 'hui''ri', NULL, 'Vi', 'Vi', '1. Estar largo (medida) 2. Extenso (tiempo)', '["Estar largo (medida)","Extenso (tiempo)"]', '["Hue hui’rí echi cusí. Está largo el palo. Hui’rí huiriri echi ucuí. Estaba lloviendo por mucho tiempo. Hui’rira. Vt Alargar. Hui’ribé. Muy extenso."]', '[]', 'Hue hui’rí echi cusí. Está largo el palo. Hui’rí huiriri echi ucuí. Estaba lloviendo por mucho tiempo. Hui’rira. Vt Alargar. Hui’ribé. Muy extenso.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
('RD-001017', 'Huirí', 'Huirí', 'huiri', NULL, 'Vi', 'Vi', 'Estar parado', '["Estar parado"]', '["¿Cumi huirí echi pichira? ¿Dónde está parada la escoba? [fut.: huiriméa; pl.: jahui]."]', '["fut.: huiriméa; pl.: jahui"]', '¿Cumi huirí echi pichira? ¿Dónde está parada la escoba? [fut.: huiriméa; pl.: jahui].', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
('RD-001018', 'Huiríami', 'Huiríami', 'huiriami', NULL, 'Adj', 'Adj', 'Parado, nacido', '["Parado, nacido"]', '["Echi bachá huiríami ranara ju. Es el hijo primogénito."]', '[]', 'Echi bachá huiríami ranara ju. Es el hijo primogénito.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
('RD-001019', 'Huiriba', 'Huiriba', 'huiriba', NULL, 'Vi sing', 'Vi', 'Pararse (el hecho de pararse)', '["Pararse (el hecho de pararse)"]', '["Echo’ná yéachi huiríbari. Se paró en la puerta. [pret.: huiríbari; fut.: huiribama; pl.: jaba]. Huiribá imper Párate"]', '["pret.: huiríbari; fut.: huiribama; pl.: jaba"]', 'Echo’ná yéachi huiríbari. Se paró en la puerta. [pret.: huiríbari; fut.: huiribama; pl.: jaba]. Huiribá imper Párate', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
