('RD-001021', 'Huiribeco', 'Huiribeco', 'huiribeco', NULL, 'Adv', 'Adv', 'Después', '["Después"]', '["Hui’ribéque nahua. Retrasa su llegada."]', '[]', 'Hui’ribéque nahua. Retrasa su llegada.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
('RD-001022', 'Hui’rique', 'Hui’rique', 'hui''rique', NULL, 'Adv', 'Adv', 'Mucho después', '["Mucho después"]', '["Hui´rique rocogó cu nahuari. Muy noche llegó. Ma hui’rique chónachi níiri. Ya era muy de noche. Hui’rique chónachi. Muy noche."]', '[]', 'Hui´rique rocogó cu nahuari. Muy noche llegó. Ma hui’rique chónachi níiri. Ya era muy de noche. Hui’rique chónachi. Muy noche.', 'SRC-02', 'DICCIONARIO raramuri.pdf', 48, 48, 'Transcrito'),
