CREATE TABLE `lexical_entries` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`record_id` text NOT NULL,
	`headword` text NOT NULL,
	`headword_raw` text NOT NULL,
	`headword_normalized` text NOT NULL,
	`homonym_number` integer,
	`classification` text DEFAULT '' NOT NULL,
	`classification_family` text NOT NULL,
	`translation_raw` text DEFAULT '' NOT NULL,
	`senses_json` text DEFAULT '[]' NOT NULL,
	`examples_json` text DEFAULT '[]' NOT NULL,
	`variants_json` text DEFAULT '[]' NOT NULL,
	`comments_raw` text DEFAULT '' NOT NULL,
	`source_code` text NOT NULL,
	`source_document` text NOT NULL,
	`page_start` integer NOT NULL,
	`page_end` integer NOT NULL,
	`status` text DEFAULT 'Transcrito' NOT NULL
);
